import { panelStyle } from '@/features/admin/shared';
import { useRequestComments, useRequestDeleteComment } from '@/hooks/useAdminRequest';

interface CommentSearchValues {
  id?: number;
  userId?: number;
  entityType?: string;
  entityId?: number;
  status?: number;
}

