              />
            </Form.Item>
            <Form.Item>
              <Space>
                <Button
                  type="primary"
                  htmlType="submit"
                  icon={<SearchOutlined />}
                  loading={commentsRequest.loading}
                >
                  搜索
                </Button>
                <Button
                  onClick={() => {
                    form.resetFields();
                    setHasSearched(false);
                  }}
                >
                  重置
                </Button>
              </Space>
            </Form.Item>
          </Form>
        </ProCard>

        {!hasSearched ? (
          <Alert
            type="info"
            showIcon
            message="评论检索要求至少填写一个筛选条件"
          />
